ьным проектам", "parent_path": "Акционерное общество \"Агрохолдинг\"Просторы\"/11.1. Семеренко Алина Сергеевна – Помощник генерального директора", "path": "Акционерное общество \"Агрохолдинг\"Просторы\"/11.1. Семеренко Алина Сергеевна – Помощник генерального директора/Дирекция по специальным проектам", "head": "3764", "emps": ["3764"]}]';
$flat = json_decode($json, true);

foreach($flat as $f) {
    $parent_id = 0;
    if ($f['parent_path'] && isset($paths[$f['parent_path']])) {
        $parent_id = $paths[$f['parent_path']];
    }
    
    $fields = [
        'ACTIVE' => 'Y',
        'IBLOCK_ID' => $IBLOCK_ID,
        'NAME' => $f['name'],
        'IBLOCK_SECTION_ID' => $parent_id,
        'UF_HEAD' => $f['head']
    ];
    
    $id = $bs->Add($fields);
    if (!$id) {
        echo "Error adding ".$f['name'].": ".$bs->LAST_ERROR."\n";
        continue;
    }
    
    $paths[$f['path']] = $id;
    echo "Added ".$f['name']." (ID: $id, Parent: $parent_id, Head: ".$f['head'].")\n";
    
    foreach($f['emps'] as $uid) {
        if (!isset($user_depts[$uid])) $user_depts[$uid] = [];
        $user_depts[$uid][] = $id;
    }
}

// 2. UPDATE USERS
foreach($user_depts as $uid => $depts) {
    echo "Updating user #$uid departments... ";
    $user = new CUser;
    // UF_DEPARTMENT expects array
    $res = $user->Update($uid, ['UF_DEPARTMENT' => $depts]);
    if ($res) echo "OK\n"; else echo "Error: ".$user->LAST_ERROR."\n";
}

echo "\nStructure rebuild complete!\n";
